// Parse ingest JSON stdout; write envelope to temp file (safe-by-construction stdin pipe, R-08).
// Envelope content (which may contain shell metacharacters) never touches the command string.
const stdout = $input.first().json.stdout;
if (!stdout || !stdout.trim()) {
  throw new Error('ingest returned no stdout -- check CLICKUP_API_KEY/DATADOG_API_KEY env vars on worker');
}
let envelope;
try {
  envelope = JSON.parse(stdout.trim());
} catch (e) {
  throw new Error('ingest stdout is not valid JSON: ' + e.message);
}
if (envelope.status === 'error') {
  throw new Error('ingest failed: ' + envelope.result.text);
}
// Write to temp file so agent-turn can read it from stdin without shell interpolation.
const fs = require('fs');
const tmpPath = '/tmp/st-at-' + Date.now() + '.json';
fs.writeFileSync(tmpPath, JSON.stringify(envelope));
const cfg = $('Set (Configure)').first().json;
return [{
  json: {
    tmpPath: tmpPath,
    githubOwner: cfg.githubOwner,
    githubRepo: cfg.githubRepo,
    githubBase: cfg.githubBase
  }
}];

// Parse agent-turn JSON stdout; write envelope to temp file for output verb stdin.
// Exit code 0 covers both 'ok' AND 'needs-input' (AC7) -- route downstream on status field.
const stdout = $input.first().json.stdout;
if (!stdout || !stdout.trim()) {
  throw new Error('agent-turn returned no stdout -- is the claude binary installed on the worker?');
}
let envelope;
try {
  envelope = JSON.parse(stdout.trim());
} catch (e) {
  throw new Error('agent-turn stdout is not valid JSON: ' + e.message);
}
// Write envelope to temp file for safe stdin piping (R-08).
const fs = require('fs');
const tmpPath = '/tmp/st-out-' + Date.now() + '.json';
fs.writeFileSync(tmpPath, JSON.stringify(envelope));
const prev = $('Code: Prep agent-turn').first().json;
return [{
  json: {
    tmpPath: tmpPath,
    envelopeStatus: envelope.status,
    githubOwner: prev.githubOwner,
    githubRepo: prev.githubRepo,
    githubBase: prev.githubBase
  }
}];

// Parse output verb result and extract the created PR or issue URL from artifacts.
const stdout = $input.first().json.stdout;
if (!stdout || !stdout.trim()) {
  throw new Error('output verb returned no stdout');
}
let envelope;
try {
  envelope = JSON.parse(stdout.trim());
} catch (e) {
  throw new Error('output verb stdout is not valid JSON: ' + e.message);
}
const artifact = envelope.artifacts.find(function(a) { return a.type === 'pr' || a.type === 'issue'; });
return [{
  json: {
    status: envelope.status,
    prUrl: artifact ? artifact.url : null,
    resultText: envelope.result.text,
    correlationId: envelope.correlationId
  }
}];

// The agent asked a clarifying question (status: 'needs-input').
// result.text contains the question text. Extend this branch to:
//   - Post the question to Slack with n8n's Slack node
//   - Wait for a response via Slack HITL or webhook
//   - Feed the answer back into a new agent-turn invocation
const prev = $('Code: Prep output').first().json;
return [{
  json: {
    status: 'needs-input',
    message: 'Agent needs human input -- extend this branch for HITL handling',
    tmpPath: prev.tmpPath
  }
}];
